from z3 import *

# Definindo as variáveis para cada questão
q = {i: Bool(f'q{i}') for i in range(1, 7)}

# Dificuldades e Tópicos de cada questão
dificuldades = {
    1: 'Facil', 2: 'Facil', 3: 'Medio', 4: 'Medio', 5: 'Medio', 6: 'Dificil'
}
topicos = {
    1: ['T1'], 2: ['T3'], 3: ['T1', 'T3'], 4: ['T4'], 5: ['T1', 'T4'], 6: ['T3', 'T4']
}

solver = Solver()

# Regra: Total de 6 questões
solver.add(Sum([If(q[i], 1, 0) for i in range(1, 7)]) == 6)

# Regra: Pelo menos 1 de cada tópico
for t in ['T1', 'T2', 'T3', 'T4']:
    questoes_com_t = [q[i] for i in range(1, 7) if t in topicos[i]]
    if not questoes_com_t:
        solver.add(False) # Tópico inexistente no banco
    else:
        solver.add(Or(questoes_com_t))

# Regra: Exatamente 1 difícil, 2 fáceis, 3 médias
solver.add(Sum([If(And(q[i], dificuldades[i] == 'Dificil'), 1, 0) for i in range(1, 7)]) == 1)
solver.add(Sum([If(And(q[i], dificuldades[i] == 'Facil'), 1, 0) for i in range(1, 7)]) == 2)
solver.add(Sum([If(And(q[i], dificuldades[i] == 'Medio'), 1, 0) for i in range(1, 7)]) == 3)

# Execução
if solver.check() == sat:
    print("SAT")
else:
    print("UNSAT")
